-- 10 أسئلة وأجوبة أولية — عينة موثوقة المصدر (لا الحصة الكاملة 30 بعد،
-- راجع التقرير النهائي لتفاصيل الفجوة). كل سؤال status='draft'،
-- is_approved=false — بانتظار مراجعة علمية بشرية إلزامية قبل النشر.
INSERT INTO dawah_questions (category_id, slug, title, short_answer, detailed_answer, evidences, glossary_terms, sources, keywords, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'does-god-exist',
'كيف أعرف أن الله موجود؟',
'من خلال العقل والفطرة والنظام الدقيق في الكون: وجود كل أثر مُحكَم يدل على صانع، والكون بدقته وقوانينه الثابتة أثر يدل على خالق حكيم.',
'يستدل العقل على وجود الله بعدة طرق متكاملة: أولًا دليل الفطرة، فالإنسان يشعر فطريًا بوجود قوة عليا خالقة دون تعليم مسبق، وهذا شعور عام عبر الثقافات الإنسانية المختلفة. ثانيًا دليل النظام والإحكام: الكون يسير بقوانين فيزيائية دقيقة ثابتة (الجاذبية، حركة الأفلاك، خصائص الذرة) لا يمكن أن تنشأ صدفة بلا مُدبِّر حكيم، تمامًا كما لا يمكن لآلة معقدة أن تتشكل من فوضى عشوائية. ثالثًا دليل الحدوث: كل ما في الكون حادث (له بداية)، والحادث لا بد له من مُحدِث ليس هو نفسه حادثًا، وإلا لتسلسلت الأسباب إلى ما لا نهاية وهو محال عقلًا. القرآن نفسه يدعو إلى هذا التفكر العقلي المباشر في الكون كطريق لمعرفة الله، لا يطلب إيمانًا أعمى بلا دليل.',
'[{"type":"quran","ref":"الطور: ٣٥-٣٦","text":"أَمْ خُلِقُوا مِنْ غَيْرِ شَيْءٍ أَمْ هُمُ الْخَالِقُونَ * أَمْ خَلَقُوا السَّمَاوَاتِ وَالْأَرْضَ ۚ بَل لَّا يُوقِنُونَ"}]'::jsonb,
'[{"term":"الفطرة","definition":"الاستعداد الغريزي الفطري في الإنسان لمعرفة الله وميله الطبيعي نحو التوحيد قبل أي تأثير خارجي."}]'::jsonb,
'[]'::jsonb,
ARRAY['وجود الله','دليل عقلي','الخالق'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='purpose-of-life'), 'purpose-of-life',
'ما الغاية من خلقنا؟',
'خلقنا الله لغاية واضحة: عبادته وحده، وهي مفهوم واسع يشمل كل عمل صالح يُقصَد به وجه الله، لا الطقوس فقط.',
'يجيب الإسلام عن سؤال الغاية من الوجود إجابة صريحة لا لبس فيها: خُلق الإنسان لعبادة الله وحده. لكن "العبادة" في التصور الإسلامي مفهوم شامل واسع، لا يقتصر على الصلاة والصيام، بل يشمل كل قول أو عمل يحبه الله ويرضاه: الصدق، والعدل، والإحسان للناس، والعمل النافع، وإعمار الأرض — طالما اقترن بنية صادقة وابتغاء وجه الله. هذا يمنح الحياة معنى متماسكًا: لست هنا صدفة عابرة بلا هدف، بل لك غاية محددة تربط تفاصيل حياتك اليومية الصغيرة بمعنى أكبر، وتمنحك معيارًا أخلاقيًا ثابتًا لا يتغير بتغير الأهواء أو الظروف.',
'[{"type":"quran","ref":"الذاريات: ٥٦","text":"وَمَا خَلَقْتُ الْجِنَّ وَالْإِنسَ إِلَّا لِيَعْبُدُونِ"}]'::jsonb,
'[{"term":"العبادة","definition":"اسم جامع لكل ما يحبه الله ويرضاه من الأقوال والأعمال الظاهرة والباطنة، وليس مقصورًا على الشعائر التعبدية فقط."}]'::jsonb,
'[]'::jsonb,
ARRAY['الغاية من الحياة','معنى الوجود','العبادة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'why-need-prophets',
'لماذا نحتاج إلى أنبياء؟',
'لأن العقل وحده، رغم أهميته، لا يكفي لمعرفة تفاصيل ما يرضي الله وكيفية عبادته — الأنبياء رسل يبلّغون هذا الوحي بدقة ووضوح.',
'العقل الإنساني قادر على إدراك وجود الخالق إجمالًا عبر التفكر في الكون، لكنه يعجز عن معرفة تفاصيل دقيقة مثل: كيف يريد الله أن نعبده؟ ما الأخلاق التي يرضاها بالضبط في كل موقف؟ ماذا بعد الموت؟ هنا تأتي الحاجة إلى الوحي والأنبياء: بشر مختارون من الله، معصومون من الكذب في التبليغ، يوصلون رسالة الله للناس بوضوح ودقة، ويكونون قدوة عملية حية لتطبيقها، لا مجرد ناقلي نظرية مجردة. الإسلام يعلّم أن الله أرسل أنبياء كثيرين عبر التاريخ لأمم مختلفة (منهم من ذُكر في القرآن كنوح وإبراهيم وموسى وعيسى عليهم السلام)، وأن محمدًا ﷺ خاتمهم ورسالته للناس كافة لا لقوم بعينهم.',
'[{"type":"quran","ref":"النساء: ١٦٥","text":"رُّسُلًا مُّبَشِّرِينَ وَمُنذِرِينَ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَى اللَّهِ حُجَّةٌ بَعْدَ الرُّسُلِ"}]'::jsonb,
'[{"term":"الوحي","definition":"إعلام الله لأنبيائه بشرعه وأحكامه بطريقة خاصة يختارها الله، تختلف عن الإلهام العام أو التفكير البشري المجرد."}]'::jsonb,
'[]'::jsonb,
ARRAY['النبوة','الأنبياء','الرسالة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='quran'), 'quran-preserved',
'كيف حُفظ القرآن من التحريف؟',
'حُفظ القرآن بطريقتين متلازمتين منذ نزوله: التدوين الكتابي الفوري في عهد النبي ﷺ، والحفظ الشفهي المتواتر جيلًا بعد جيل حتى اليوم.',
'اعتنى المسلمون بحفظ القرآن منذ لحظة نزوله بطريقة فريدة لم تتوفر لأي نص قديم آخر بنفس الدرجة: أولًا كان الصحابة يكتبون الآيات فور نزولها بإشراف مباشر من النبي ﷺ، وثانيًا كان كثير منهم يحفظون القرآن كاملًا عن ظهر قلب (وهذا مستمر إلى اليوم بالملايين حول العالم عبر التلقي المباشر من معلم إلى تلميذ بسند متصل، لا بالقراءة الفردية فقط). هذا الجمع بين التوثيق الكتابي والحفظ الشفهي المتواتر (نقل جماعة كبيرة يستحيل تواطؤها على الكذب) يجعل احتمال دخول تحريف دون كشفه فوريًا شبه مستحيل عمليًا: أي تغيير في كلمة واحدة في نسخة مطبوعة حديثة سيتناقض فورًا مع ملايين الحفّاظ حول العالم ومع النسخ المخطوطة القديمة المحفوظة في متاحف ومكتبات عالمية.',
'[{"type":"quran","ref":"الحجر: ٩","text":"إِنَّا نَحْنُ نَزَّلْنَا الذِّكْرَ وَإِنَّا لَهُ لَحَافِظُونَ"}]'::jsonb,
'[{"term":"التواتر","definition":"نقل خبر أو نص عبر عدد كبير من الرواة في كل طبقة يستحيل عادة تواطؤهم على الكذب، بحيث يفيد العلم اليقيني بصحة المنقول."}]'::jsonb,
'[]'::jsonb,
ARRAY['حفظ القرآن','تحريف','التواتر'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='worship'), 'why-pray-five-times',
'لماذا نصلي خمس مرات يوميًا؟',
'الصلاة ليست عبئًا بل تذكير دوري يربطك بالله عبر يومك، ويحفظ توازنك الروحي والأخلاقي بشكل متكرر لا مرة واحدة أسبوعيًا أو سنويًا.',
'فُرضت الصلوات الخمس بتوزيع يغطي أوقات اليوم المختلفة (الفجر، الظهر، العصر، المغرب، العشاء) بحكمة واضحة: تكرار متقارب يمنع الغفلة الطويلة عن ذكر الله، ويمنحك محطات توقف منتظمة للمراجعة الذاتية وسط انشغالات الحياة اليومية. عمليًا، كل صلاة لا تستغرق أكثر من دقائق معدودة، وهي في الوقت نفسه تدريب يومي متكرر على الانضباط والحضور الذهني، وتذكير مباشر بالله في لحظات العمل والانشغال الدنيوي بدل أن يقتصر التديّن على مناسبة واحدة أسبوعية. من لم يعتد الصلاة بعد، النصيحة الثابتة: ابدأ بصلاة واحدة تتقنها، ثم أضف غيرها تدريجيًا.',
'[{"type":"quran","ref":"العنكبوت: ٤٥","text":"إِنَّ الصَّلَاةَ تَنْهَىٰ عَنِ الْفَحْشَاءِ وَالْمُنكَرِ"}]'::jsonb,
'[]'::jsonb,
'[]'::jsonb,
ARRAY['الصلاة','العبادة اليومية'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='ethics'), 'islam-and-morality',
'هل الأخلاق في الإسلام ثابتة أم نسبية؟',
'الأخلاق الكبرى في الإسلام (الصدق، العدل، الأمانة، الرحمة) ثوابت لا تتغير بتغير المجتمع أو الزمان، لأنها مستمَدة من الوحي لا من الهوى أو العرف المتقلب.',
'يرى الإسلام أن الأخلاق الأساسية ليست اختراعًا بشريًا متغيرًا حسب الثقافة أو الزمن، بل قيم ثابتة مصدرها الوحي الإلهي: الصدق حسن دائمًا والكذب قبيح دائمًا، العدل واجب دائمًا والظلم محرَّم دائمًا، بصرف النظر عن رأي المجتمع أو العصر. هذا لا يعني جمودًا في كل التفاصيل: هناك مساحة اجتهاد فقهي في كيفية تطبيق بعض الأحكام حسب الزمان والمكان (كوسائل تحقيق العدل مثلًا)، لكن جوهر القيمة الأخلاقية ذاته ثابت. هذا الثبات في نظر الإسلام ميزة لا عيب: فالأخلاق النسبية بالكامل (التي تتغير كليًا حسب هوى المجتمع) لا تستطيع إدانة ظلم واضح إن ارتضاه مجتمع بعينه في زمن ما، بينما الأخلاق المبنية على مرجعية ثابتة تمنح معيارًا حقيقيًا للحكم على الصواب والخطأ.',
'[{"type":"hadith","ref":"رواه الترمذي، كتاب البر والصلة، وحسّنه بعض أهل العلم","grading":"يحتاج تحقق المراجع العلمي قبل الاعتماد على الدرجة بدقة","text":"اتَّقِ اللَّهَ حَيْثُمَا كُنْتَ، وَأَتْبِعِ السَّيِّئَةَ الْحَسَنَةَ تَمْحُهَا، وَخَالِقِ النَّاسَ بِخُلُقٍ حَسَنٍ"}]'::jsonb,
'[]'::jsonb,
'[]'::jsonb,
ARRAY['الأخلاق','القيم','النسبية الأخلاقية'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'women-status-islam',
'ما مكانة المرأة في الإسلام؟',
'كرّم الإسلام المرأة إنسانًا كامل الكرامة مساويًا للرجل في أصل الخلقة والتكليف الديني، مع تنظيم أدوار أسرية متكاملة لا متطابقة بالضرورة بين الجنسين.',
'يقرر الإسلام مساواة أصلية بين الرجل والمرأة في الكرامة الإنسانية وأصل الخلق، وفي الثواب والعقاب الأخروي على الأعمال، وفي التكليف الديني (الصلاة والصيام والزكاة والحج). في الجانب الاجتماعي والأسري، ينظّم الإسلام أدوارًا يراها متكاملة لا متطابقة بالضرورة: كالنفقة الواجبة على الرجل، وحقوق الميراث والمهر، وهذا التنظيم موضوع نقاش وتفصيل واسع تختلف فيه القراءات والسياقات، ويستحق معالجة مستقلة لكل مسألة (كالميراث والحجاب وتعدد الزوجات) بتفصيلها الخاص لا اختزالًا في جواب واحد عام. النقطة الجوهرية التي يؤكدها الإسلام: قيمة المرأة الإنسانية والدينية لا تقل عن الرجل، وإن اختلفت بعض الأدوار الاجتماعية المنظَّمة شرعًا.',
'[{"type":"quran","ref":"النحل: ٩٧","text":"مَنْ عَمِلَ صَالِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُ حَيَاةً طَيِّبَةً"}]'::jsonb,
'[]'::jsonb,
'[]'::jsonb,
ARRAY['المرأة في الإسلام','المساواة','الأسرة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='freedom-human-rights'), 'freedom-to-question',
'هل يُسمح لي بالتساؤل والشك؟',
'نعم — الإسلام يدعو صراحة إلى التفكر والتدبر والسؤال، ولا يطلب إيمانًا أعمى بلا فهم أو دليل.',
'خلافًا لتصور شائع، يشجّع القرآن نفسه على التفكر والتساؤل والتدبر باعتباره طريقًا لليقين لا عائقًا له. المطلوب من الباحث عن الحقيقة أن يسأل ويتحقق، لا أن يقبل بلا فهم. كثير من كبار علماء الإسلام مرّوا بمراحل شك وتساؤل عميق قبل أن يصلوا إلى يقين مبني على دليل وفهم، وهذا مسار طبيعي محترَم لا معيب. هذه المنصة نفسها مبنية على هذا المبدأ: لا ضغط عاطفي، ولا إلزام بالإيمان قبل الاقتناع — فقط عرض الأدلة والإجابات، والقرار قرارك.',
'[{"type":"quran","ref":"آل عمران: ١٩١","text":"الَّذِينَ يَذْكُرُونَ اللَّهَ قِيَامًا وَقُعُودًا وَعَلَىٰ جُنُوبِهِمْ وَيَتَفَكَّرُونَ فِي خَلْقِ السَّمَاوَاتِ وَالْأَرْضِ"}]'::jsonb,
'[]'::jsonb,
'[]'::jsonb,
ARRAY['حرية السؤال','الشك','التفكر'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='science-religion'), 'islam-and-science',
'هل يتعارض الإسلام مع العلم؟',
'لا — الإسلام يدعو صراحة إلى طلب العلم والتفكر في الكون، ولا يوجد تعارض أصولي بين النص الشرعي الصحيح والحقيقة العلمية الثابتة.',
'يحض القرآن والسنة على طلب العلم والتفكر في الكون كوسيلة لمعرفة عظمة الخالق، وقد شهد التاريخ الإسلامي ازدهارًا علميًا واسعًا في الطب والفلك والرياضيات استند جزء منه إلى هذا الحث الديني على البحث والتأمل. من المهم التمييز بين ثلاثة أمور غالبًا ما تُخلَط: (١) النص القرآني الثابت قطعي الدلالة، (٢) التفسيرات البشرية له التي قد تصيب أو تخطئ، (٣) النظريات العلمية القابلة للتطور والمراجعة. حين يُدَّعى وجود "تعارض"، غالبًا ما يكون الخلاف في تفسير بشري معيّن للنص لا في النص ذاته، أو في نظرية علمية غير مستقرة بعد. الإسلام لا يخشى السؤال العلمي، بل يدعو إليه.',
'[{"type":"quran","ref":"طه: ١١٤","text":"وَقُل رَّبِّ زِدْنِي عِلْمًا"}]'::jsonb,
'[]'::jsonb,
'[]'::jsonb,
ARRAY['الإسلام والعلم','التعارض المزعوم'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='qadar'), 'qadar-and-free-will',
'إذا كان كل شيء مقدَّرًا، فلماذا نُحاسَب؟',
'القدر لا يلغي إرادتك الحرة الحقيقية في الاختيار — الله يعلم مسبقًا ماذا ستختار، لكن علمه بالاختيار لا يعني إجبارك عليه.',
'من أدق مسائل العقيدة وأكثرها التباسًا: الإيمان بالقدر لا يعني أن الإنسان مُجبَر على أفعاله كالآلة. التصور الإسلامي الوسط: لله علم أزلي شامل بكل ما سيحدث (بما في ذلك اختيارات البشر)، لكن هذا العلم المسبق لا يُلغي حقيقة أن الإنسان يختار فعله بإرادته الحقيقية في لحظة الفعل. مثال تقريبي: معلّم يعرف مسبقًا (بخبرته) أن طالبًا معينًا سيرسب لأنه لا يذاكر — هذا العلم المسبق لم يُجبر الطالب على عدم المذاكرة، الطالب اختار ذلك بنفسه، والمعلّم فقط عَلِمَ ما سيختاره. على هذا الأساس يُحاسَب الإنسان على اختياره الحر، لا على علم الله المسبق به. هذه مسألة عميقة قد تحتاج نقاشًا موسّعًا، ولذلك ننصح بمراجعة داعية مباشرة لمزيد تفصيل إن استمر الإشكال.',
'[{"type":"quran","ref":"الكهف: ٢٩","text":"فَمَن شَاءَ فَلْيُؤْمِن وَمَن شَاءَ فَلْيَكْفُرْ"}]'::jsonb,
'[]'::jsonb,
'[]'::jsonb,
ARRAY['القضاء والقدر','حرية الإرادة','الجبر والاختيار'], 'draft', false)
ON CONFLICT (slug) DO NOTHING;
